function Insert-Data($table, $jsonBody) {
    $tmpFile = [System.IO.Path]::GetTempFileName()
    [System.IO.File]::WriteAllText($tmpFile, $jsonBody, [System.Text.Encoding]::UTF8)
    $result = curl.exe -s -o /dev/null -w "%{http_code}" -X POST "$base/$table" `
        -H "apikey: $key" `
        -H "Authorization: Bearer $key" `
        -H "Content-Type: application/json; charset=utf-8" `
        -H "Prefer: return=minimal,resolution=ignore-duplicates" `
        --data-binary "@$tmpFile"
    Remove-Item $tmpFile -Force
    return $result
}

